I will begin by generating the comprehensive SQL setup for the **Referral and Bonus system**. This includes updating the `profiles` table with referral codes, creating the `referral_earnings` table, and implementing the secure **Database Functions (RPCs)** to handle commission calculations automatically whenever a deposit is approved or a bet is lost.

Since we are on Termux, I am continuing to use **Secure RPCs** instead of Edge Functions to ensure everything works perfectly without CLI dependencies.

### 🚀 ACTION REQUIRED: Step 1 - Run this SQL
Please run this in your **Supabase Dashboard -> SQL Editor**:

```sql
-- 1. Update Profiles Table
alter table public.profiles 
  add column if not exists referral_code text unique,
  add column if not exists referred_by uuid references public.profiles(id),
  add column if not exists total_referral_earnings numeric default 0;

-- 2. Create Referral Earnings Table
create table if not exists public.referral_earnings (
  id uuid default gen_random_uuid() primary key,
  referrer_id uuid references public.profiles(id) not null,
  referred_user_id uuid references public.profiles(id) not null,
  from_type text check (from_type in ('deposit', 'bet_loss')),
  amount numeric not null,
  transaction_id uuid references public.transactions(id),
  created_at timestamp with time zone default now()
);

-- 3. Update App Settings for Referrals
alter table public.app_settings
  add column if not exists referral_deposit_bonus_percent numeric default 10.0,
  add column if not exists referral_bet_loss_bonus_percent numeric default 5.0,
  add column if not exists min_deposit_for_bonus numeric default 500.0;

-- 4. Enable RLS and Policies
alter table public.referral_earnings enable row level security;
create policy "Users can view own referral earnings" on referral_earnings for select using (auth.uid() = referrer_id);
create policy "Admins can view all referral earnings" on referral_earnings for select using (public.is_admin());

-- 5. Helper Function: Generate Random Referral Code
create or replace function public.generate_referral_code() 
returns text as $$
declare
  chars text := 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  result text := '';
  i integer := 0;
begin
  for i in 1..8 loop
    result := result || substr(chars, floor(random() * length(chars) + 1)::integer, 1);
  end loop;
  return result;
end;
$$ language plpgsql;

-- 6. Update handle_new_user trigger to generate code and handle referral link
create or replace function public.handle_new_user()
returns trigger as $$
declare
  v_ref_code text;
  v_referrer_id uuid;
begin
  -- Generate unique code for the new user
  v_ref_code := public.generate_referral_code();

  -- Check if a referral code was provided in metadata
  if (new.raw_user_meta_data->>'referral_code') is not null then
    select id into v_referrer_id from public.profiles where referral_code = (new.raw_user_meta_data->>'referral_code');
  end if;

  insert into public.profiles (id, username, balance, referral_code, referred_by)
  values (
    new.id, 
    coalesce(new.raw_user_meta_data->>'username', 'User_' || substr(new.id::text, 1, 5)), 
    10000.00,
    v_ref_code,
    v_referrer_id
  );
  return new;
end;
$$ language plpgsql security definer;

-- 7. Secure RPC to process Referral Bonus on Bet Loss
-- This is called securely when a round ends and a user loses
create or replace function public.process_loss_referral_bonus(
  p_user_id uuid,
  p_loss_amount numeric,
  p_bet_id uuid
)
returns void
language plpgsql
security definer
as $$
declare
  v_referrer_id uuid;
  v_bonus_percent numeric;
  v_bonus_amount numeric;
begin
  -- 1. Find the referrer
  select referred_by into v_referrer_id from public.profiles where id = p_user_id;

  if v_referrer_id is not null then
    -- 2. Get settings
    select referral_bet_loss_bonus_percent into v_bonus_percent from public.app_settings where id = 1;

    -- 3. Calculate bonus
    v_bonus_amount := (p_loss_amount * v_bonus_percent) / 100;

    if v_bonus_amount > 0 then
      -- 4. Credit referrer
      update public.profiles 
      set balance = balance + v_bonus_amount,
          total_referral_earnings = total_referral_earnings + v_bonus_amount
      where id = v_referrer_id;

      -- 5. Log the earning
      insert into public.referral_earnings (referrer_id, referred_user_id, from_type, amount)
      values (v_referrer_id, p_user_id, 'bet_loss', v_bonus_amount);
    end if;
  end if;
end;
$$;

-- 8. Update admin_process_deposit to handle referral bonus
create or replace function public.admin_process_deposit(
  p_transaction_id uuid,
  p_approve boolean,
  p_reason text default null
)
returns json
language plpgsql
security definer
as $$
declare
  v_tx record;
  v_referrer_id uuid;
  v_bonus_percent numeric;
  v_bonus_amount numeric;
begin
  if not public.is_admin() then
    return json_build_object('error', 'Unauthorized');
  end if;

  select * into v_tx from public.transactions where id = p_transaction_id for update;
  if not found or v_tx.status != 'pending' or v_tx.type != 'deposit' then
    return json_build_object('error', 'Transaction not found or already processed');
  end if;

  if p_approve then
    update public.transactions set status = 'completed' where id = p_transaction_id;
    update public.profiles set balance = balance + v_tx.amount where id = v_tx.user_id;

    -- REFERRAL LOGIC FOR DEPOSIT
    select referred_by into v_referrer_id from public.profiles where id = v_tx.user_id;
    if v_referrer_id is not null then
       select referral_deposit_bonus_percent into v_bonus_percent from public.app_settings where id = 1;
       v_bonus_amount := (v_tx.amount * v_bonus_percent) / 100;

       if v_bonus_amount > 0 then
         update public.profiles 
         set balance = balance + v_bonus_amount,
             total_referral_earnings = total_referral_earnings + v_bonus_amount
         where id = v_referrer_id;

         insert into public.referral_earnings (referrer_id, referred_user_id, from_type, amount, transaction_id)
         values (v_referrer_id, v_tx.user_id, 'deposit', v_bonus_amount, p_transaction_id);
       end if;
    end if;
  else
    update public.transactions set status = 'failed', details = jsonb_set(details, '{rejection_reason}', to_jsonb(p_reason)) where id = p_transaction_id;
  end if;

  return json_build_object('success', true);
end;
$$;
```

I will now update the **Registration flow**, the **Promotion/Referral UI**, and the **Admin Panel** to support these new features.

