          )}

          {tab === 'referral' && <ReferralTab />}

          {tab === 'promo' && (
            <div className="space-y-4">
              <div className="bg-gradient-to-r from-red-600 to-red-900 p-6 rounded-[2rem] text-white shadow-xl relative overflow-hidden">
                <div className="relative z-10">
                  <h4 className="text-xl font-black italic uppercase">First Deposit Bonus</h4>
                  <p className="text-[10px] font-bold text-red-200 mb-4 tracking-widest uppercase">Get extra 10% on deposits above ₹500</p>
                  <span className="bg-white text-red-600 px-3 py-1 rounded-full text-[10px] font-black uppercase">Active Now</span>
                </div>
                <div className="absolute -bottom-4 -right-4 text-white opacity-10">
                  <Wallet size={100} />
                </div>
              </div>
              <div className="bg-gray-800 p-6 rounded-[2rem] border border-gray-700">
                <h4 className="text-white font-black italic uppercase mb-1">Daily Login Bonus</h4>
                <p className="text-gray-400 text-xs font-medium">Coming soon... Stay tuned for daily rewards!</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { useGameStore } from '../store/gameStore';

export default function AuthPage() {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [email, setEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [referralCode, setReferralCode] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { addToast } = useGameStore();

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (mode === 'register') {
        const { data: authData, error: authError } = await supabase.auth.signUp({
          email,
          password,
          options: { 
            data: { 
              username,
              referral_code: referralCode
            } 
          }
        });

        if (authError) throw authError;
        if (authData.user) {
          addToast('success', 'Registration successful! Verification email sent.');
        }
      } else {
        const { error: loginError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });

        if (loginError) throw loginError;
        addToast('success', 'Welcome back!');
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-950 flex flex-col items-center justify-center px-4">
      <div className="mb-8 text-center animate-in fade-in zoom-in duration-700">
        <div className="flex items-center justify-center gap-2 mb-2">
          <span className="text-5xl font-black text-white italic tracking-tighter">66</span>
          <span className="text-3xl font-bold text-red-600 uppercase tracking-widest">Lottery</span>
        </div>
        <p className="text-gray-500 text-xs font-black uppercase tracking-[0.3em]">Premium Prediction</p>
      </div>

      <div className="w-full max-w-sm bg-gray-900 rounded-[2.5rem] p-8 border border-gray-800 shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-red-600 to-transparent opacity-50"></div>

        <div className="flex rounded-2xl overflow-hidden mb-8 bg-gray-800 p-1 border border-gray-700/50">
          <button
            onClick={() => { setMode('login'); setError(''); }}
            className={`flex-1 py-3 text-xs font-black uppercase tracking-widest transition-all rounded-xl ${
              mode === 'login' ? 'bg-red-600 text-white shadow-lg' : 'text-gray-500'
            }`}
          >
            Login
          </button>
          <button
            onClick={() => { setMode('register'); setError(''); }}
            className={`flex-1 py-3 text-xs font-black uppercase tracking-widest transition-all rounded-xl ${
              mode === 'register' ? 'bg-red-600 text-white shadow-lg' : 'text-gray-500'
            }`}
          >
            Register
          </button>
        </div>

        <form onSubmit={handleAuth} className="space-y-5">
          {mode === 'register' && (
            <div className="space-y-1">
              <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Username</label>
              <input
                type="text"
                value={username}
                onChange={e => setUsername(e.target.value)}
                placeholder="Choose profile name"
                required
                className="w-full bg-gray-800 border-2 border-gray-700 rounded-2xl px-5 py-3.5 text-white text-sm focus:outline-none focus:border-red-600 transition-all placeholder:text-gray-600 font-bold"
              />
            </div>
          )}
          <div className="space-y-1">
            <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Email Address</label>
            <input
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="Enter secure email"
              required
              className="w-full bg-gray-800 border-2 border-gray-700 rounded-2xl px-5 py-3.5 text-white text-sm focus:outline-none focus:border-red-600 transition-all placeholder:text-gray-600 font-bold"
            />
          </div>
          <div className="space-y-1">
            <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Password</label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="••••••••"
              required
              className="w-full bg-gray-800 border-2 border-gray-700 rounded-2xl px-5 py-3.5 text-white text-sm focus:outline-none focus:border-red-600 transition-all placeholder:text-gray-600 font-bold"
            />
          </div>

          {mode === 'register' && (
            <div className="space-y-1">
              <label className="block text-[10px] font-black text-red-500 uppercase tracking-widest ml-1">Referral Code (Optional)</label>
              <input
                type="text"
                value={referralCode}
                onChange={e => setReferralCode(e.target.value.toUpperCase())}
                placeholder="Enter invite code"
                className="w-full bg-red-600/5 border-2 border-red-900/20 rounded-2xl px-5 py-3.5 text-red-500 text-sm focus:outline-none focus:border-red-600 transition-all placeholder:text-red-900/30 font-black tracking-widest"
              />
            </div>
          )}

          {error && (
            <div className="text-red-500 text-[10px] font-black uppercase bg-red-500/10 border border-red-500/20 rounded-xl px-4 py-3 text-center tracking-tighter">
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-red-600/20 active:scale-[0.98] uppercase tracking-[0.2em] text-xs"
          >
            {loading ? 'Processing...' : mode === 'login' ? 'Secure Login' : 'Create Profile'}
          </button>
        </form>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';
import { 
  LayoutDashboard, Users, Activity, History, CreditCard, Settings, LogOut, CheckCircle, XCircle, Wallet, Share2
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

export default function AdminPanel() {
  const { user, profile, signOut, refreshProfile } = useAuthStore();
  const { addToast } = useGameStore();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [renderError, setRenderError] = useState<string | null>(null);
  const [appSettings, setAppSettings] = useState({ upi_id: '', referral_deposit_bonus_percent: 10, referral_bet_loss_bonus_percent: 5 });

  if (renderError) {
    return (
      <div className="min-h-screen bg-red-950 flex items-center justify-center p-4 text-white">
        <div className="bg-red-900/20 border border-red-500 p-8 rounded-2xl max-w-lg w-full">
          <h1 className="text-xl font-bold mb-4">Admin Panel Crash Detected</h1>
          <pre className="bg-black/50 p-4 rounded-lg text-xs font-mono overflow-auto mb-4">{renderError}</pre>
          <button onClick={() => window.location.reload()} className="w-full bg-red-600 py-2 rounded-lg font-bold">RELOAD SYSTEM</button>
        </div>
      </div>
    );
  }

  const [stats, setStats] = useState({
    totalUsers: 0,
    activeRounds: 5,
    totalBetsToday: 0,
    houseProfit: 0,
    totalRevenue: 0,
    totalReferralPaid: 0
  });

  const [users, setUsers] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [referralEarnings, setReferralEarnings] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (profile?.is_admin) {
      fetchDashboardData();
    }
  }, [profile]);

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const { count: userCount } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
      const { data: txs } = await supabase.from('transactions').select('*').gte('created_at', new Date(Date.now() - 86400000).toISOString());
      const { data: allEarnings } = await supabase.from('referral_earnings').select('amount');

      let profit = 0;
      let revenue = 0;
      if (txs) {
        txs.forEach(tx => {
          if (tx.type === 'loss') profit += Number(tx.amount);
          if (tx.type === 'win') profit -= Number(tx.amount);
          if (tx.type === 'deposit' && tx.status === 'completed') revenue += Number(tx.amount);
        });
      }

      setStats({
        totalUsers: userCount || 0,
        activeRounds: 5,
        totalBetsToday: txs?.filter(t => t.type === 'bet').length || 0,
        houseProfit: profit,
        totalRevenue: revenue,
        totalReferralPaid: allEarnings?.reduce((sum, e) => sum + Number(e.amount), 0) || 0
      });

      const { data: userData } = await supabase.from('profiles').select('*').order('created_at', { ascending: false }).limit(50);
      if (userData) setUsers(userData);

      const { data: txData } = await supabase.from('transactions').select('*').order('created_at', { ascending: false }).limit(50);
      if (txData) setTransactions(txData);

      const { data: refData } = await supabase.from('referral_earnings').select('*, referrer:referrer_id(username), referred:referred_user_id(username)').order('created_at', { ascending: false }).limit(50);
      if (refData) setReferralEarnings(refData);

      const { data: settingsData } = await supabase.from('app_settings').select('*').eq('id', 1).single();
      if (settingsData) setAppSettings({ 
        upi_id: settingsData.upi_id || '',
        referral_deposit_bonus_percent: settingsData.referral_deposit_bonus_percent,
        referral_bet_loss_bonus_percent: settingsData.referral_bet_loss_bonus_percent
      });

    } catch (error) {
      console.error('Error fetching admin data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleProcessWithdrawal = async (txId: string, approve: boolean) => {
    try {
      const { error } = await supabase.rpc('admin_process_withdrawal', { p_transaction_id: txId, p_approve: approve });
      if (error) throw error;
      addToast('success', `Withdrawal ${approve ? 'approved' : 'rejected'}`);
      fetchDashboardData();
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleProcessDeposit = async (txId: string, approve: boolean) => {
    const reason = approve ? '' : prompt('Reason for rejection:');
    if (!approve && reason === null) return;
    try {
      const { error } = await supabase.rpc('admin_process_deposit', { p_transaction_id: txId, p_approve: approve, p_reason: reason || null });
      if (error) throw error;
      addToast('success', `Deposit ${approve ? 'approved' : 'rejected'}`);
      fetchDashboardData();
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleSaveSettings = async () => {
    try {
      const { error } = await supabase.from('app_settings').update(appSettings).eq('id', 1);
      if (error) throw error;
      addToast('success', 'Settings saved');
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleEditBalance = async (userId: string, currentBalance: number) => {
    const newBal = prompt('Enter new balance:', currentBalance.toString());
    if (!newBal) return;
    try {
      const { error } = await supabase.rpc('admin_edit_balance', { p_target_user_id: userId, p_new_balance: Number(newBal), p_reason: 'Admin Adjustment' });
      if (error) throw error;
      addToast('success', 'Balance updated');
      fetchDashboardData();
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleForceResult = async (sessionType: string) => {
    const num = prompt(`Force result for ${sessionType}\nNumber (0-9):`);
    if (num === null) return;
    const parsedNum = parseInt(num);
    if (isNaN(parsedNum) || parsedNum < 0 || parsedNum > 9) { addToast('error', 'Invalid number'); return; }
    const color = (parsedNum === 0 || parsedNum === 5) ? (parsedNum === 0 ? 'red-violet' : 'green-violet') : ([1,3,7,9].includes(parsedNum) ? 'green' : 'red');
    const bsChoice = prompt(`Calculated: ${parsedNum >= 5 ? 'Big' : 'Small'}\nEnter B/S to override:`);
    let bigSmall = parsedNum >= 5 ? 'Big' : 'Small';
    if (bsChoice?.toUpperCase() === 'B') bigSmall = 'Big';
    if (bsChoice?.toUpperCase() === 'S') bigSmall = 'Small';
    const currentPeriod = useGameStore.getState().sessions[sessionType as any].period;
    try {
      const { error } = await supabase.rpc('admin_force_result', { p_session_type: sessionType, p_period: currentPeriod, p_number: parsedNum, p_color: color, p_big_small: bigSmall });
      if (error) throw error;
      addToast('success', `Forced: ${parsedNum} (${bigSmall})`);
    } catch (err: any) { addToast('error', err.message); }
  };

  const chartData = [
    { name: 'Mon', profit: 4000 }, { name: 'Tue', profit: 3000 }, { name: 'Wed', profit: 5000 },
    { name: 'Thu', profit: 2780 }, { name: 'Fri', profit: 8890 }, { name: 'Sat', profit: 6390 },
    { name: 'Sun', profit: stats.houseProfit },
  ];

  if (!profile) return null;
  if (!profile.is_admin) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center p-4">
