          } else {
            pendingToasts.push({ type: 'loss', message: `Result: ${resultNumber}. Better luck next time!` });
          }
        }

        newCounters[st] = newCounters[st] + 1;
        const { durationSeconds } = SESSION_CONFIGS[st];

        newSessions[st] = {
