import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { FileText, ArrowRightLeft, Clock, History, CheckCircle, XCircle, Activity as ActivityIcon } from 'lucide-react';

export default function Activity() {
  const { profile } = useAuthStore();
  const [activeTab, setActiveTab] = useState<'bets' | 'transactions' | 'history'>('bets');
  const [loading, setLoading] = useState(true);
  const [bets, setBets] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [games, setGames] = useState<any[]>([]);

  useEffect(() => {
    if (profile?.id) fetchData();
  }, [profile?.id, activeTab]);

  const fetchData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'bets') {
        const { data } = await supabase
          .from('bets')
          .select('*')
          .eq('user_id', profile.id)
          .order('created_at', { ascending: false })
          .limit(50);
        if (data) setBets(data);
      } else if (activeTab === 'transactions') {
        const { data } = await supabase
          .from('transactions')
          .select('*')
          .eq('user_id', profile.id)
          .order('created_at', { ascending: false })
          .limit(50);
        if (data) setTransactions(data);
      } else if (activeTab === 'history') {
        const { data } = await supabase
          .from('games')
          .select('*')
          .order('created_at', { ascending: false })
          .limit(50);
        if (data) setGames(data);
      }
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status: string) => {
    if (status === 'completed') return <CheckCircle className="w-3 h-3 text-green-500" />;
    if (status === 'pending') return <ActivityIcon className="w-3 h-3 text-yellow-500 animate-pulse" />;
    return <XCircle className="w-3 h-3 text-red-500" />;
  };

  return (
    <div className="p-4 pb-24 animate-in fade-in slide-in-from-right duration-500">
      <div className="mb-4">
        <h2 className="text-2xl font-black italic uppercase tracking-tight text-gray-800">Activity</h2>
        <p className="text-gray-500 text-xs font-bold uppercase tracking-widest">Track your records</p>
      </div>

      {/* Tabs */}
      <div className="flex bg-white rounded-xl p-1 mb-4 shadow-sm border border-gray-100">
        {[
          { id: 'bets', label: 'My Bets', icon: FileText },
          { id: 'transactions', label: 'Transfers', icon: ArrowRightLeft },
          { id: 'history', label: 'History', icon: History }
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex-1 flex items-center justify-center gap-1.5 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab.id 
                ? 'bg-red-600 text-white shadow-md' 
                : 'text-gray-400 hover:text-gray-600 hover:bg-gray-50'
            }`}
          >
            <tab.icon className="w-3.5 h-3.5" />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Content Area */}
      <div className="bg-white rounded-3xl border border-gray-100 shadow-sm min-h-[400px] overflow-hidden">
        {loading ? (
          <div className="h-64 flex flex-col items-center justify-center gap-4 text-gray-300">
            <div className="w-8 h-8 border-4 border-gray-200 border-t-red-600 rounded-full animate-spin"></div>
            <p className="text-[10px] font-black uppercase tracking-widest animate-pulse">Syncing Database...</p>
          </div>
        ) : (
          <div className="divide-y divide-gray-50">

            {/* BETS TAB */}
            {activeTab === 'bets' && (
              bets.length === 0 ? (
                <div className="p-10 text-center text-gray-400">
                  <FileText className="w-12 h-12 mx-auto mb-2 opacity-20" />
                  <p className="text-xs font-bold uppercase tracking-widest">No bets found</p>
                </div>
              ) : (
                bets.map((bet) => (
                  <div key={bet.id} className="p-4 hover:bg-gray-50 transition-colors">
                    <div className="flex justify-between items-start mb-2">
                      <div>
                        <span className="bg-gray-100 text-gray-600 text-[10px] font-black uppercase px-2 py-0.5 rounded-md border border-gray-200 mr-2">
                          {bet.session_type}
                        </span>
                        <span className="text-xs font-bold text-gray-800 font-mono tracking-tight">{bet.period}</span>
                      </div>
                      <span className="text-[9px] font-bold text-gray-400 uppercase tracking-tighter flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {new Date(bet.created_at).toLocaleTimeString()}
                      </span>
                    </div>
                    <div className="flex items-center justify-between mt-3">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-gray-50 flex flex-col items-center justify-center border border-gray-100">
                          <span className="text-[8px] font-black uppercase text-gray-400 tracking-tighter">Bet</span>
                          <span className="text-sm font-black capitalize text-gray-800">{bet.value}</span>
                        </div>
                        <div>
                          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Amount</p>
                          <p className="text-sm font-black text-gray-800">₹{bet.amount}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Result</p>
                        {bet.won === null ? (
                          <span className="text-sm font-black text-yellow-500 animate-pulse">Pending</span>
                        ) : bet.won ? (
                          <span className="text-sm font-black text-green-600">+ ₹{bet.payout}</span>
                        ) : (
                          <span className="text-sm font-black text-red-500">- ₹{bet.amount}</span>
                        )}
                      </div>
                    </div>
                  </div>
                ))
              )
            )}

            {/* TRANSACTIONS TAB */}
            {activeTab === 'transactions' && (
              transactions.length === 0 ? (
                <div className="p-10 text-center text-gray-400">
                  <ArrowRightLeft className="w-12 h-12 mx-auto mb-2 opacity-20" />
                  <p className="text-xs font-bold uppercase tracking-widest">No transactions</p>
                </div>
              ) : (
                transactions.map((tx) => (
                  <div key={tx.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                    <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-lg ${
                        tx.type === 'deposit' ? 'bg-green-50 text-green-600' :
                        tx.type === 'withdrawal' ? 'bg-red-50 text-red-600' :
                        tx.type === 'win' ? 'bg-yellow-50 text-yellow-600' :
                        'bg-gray-100 text-gray-600'
                      }`}>
                        {tx.type === 'deposit' ? '↓' : tx.type === 'withdrawal' ? '↑' : tx.type === 'win' ? '★' : '−'}
                      </div>
                      <div>
                        <p className="text-sm font-black capitalize italic text-gray-800">{tx.type}</p>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter mt-0.5">
                          {new Date(tx.created_at).toLocaleString()}
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className={`text-base font-black ${tx.type === 'deposit' || tx.type === 'win' ? 'text-green-600' : 'text-gray-800'}`}>
                        {tx.type === 'deposit' || tx.type === 'win' ? '+' : '-'}₹{Number(tx.amount).toLocaleString()}
                      </p>
                      <div className="flex items-center justify-end gap-1 mt-1">
                        {getStatusIcon(tx.status)}
                        <span className={`text-[9px] font-black uppercase tracking-widest ${
                          tx.status === 'completed' ? 'text-green-500' : 
                          tx.status === 'pending' ? 'text-yellow-500' : 'text-red-500'
                        }`}>
                          {tx.status}
                        </span>
                      </div>
                    </div>
                  </div>
                ))
              )
            )}

            {/* HISTORY TAB */}
            {activeTab === 'history' && (
              games.length === 0 ? (
                <div className="p-10 text-center text-gray-400">
                  <History className="w-12 h-12 mx-auto mb-2 opacity-20" />
                  <p className="text-xs font-bold uppercase tracking-widest">No history yet</p>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-left text-sm">
                    <thead className="bg-gray-50 text-[10px] font-black uppercase text-gray-400 border-b border-gray-100">
                      <tr>
                        <th className="p-4 whitespace-nowrap">Period</th>
                        <th className="p-4 text-center">Number</th>
                        <th className="p-4 text-center">Size</th>
                        <th className="p-4 text-center">Color</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                      {games.map((g) => (
                        <tr key={g.id} className="hover:bg-gray-50 transition-colors">
                          <td className="p-4">
                            <span className="bg-gray-100 px-2 py-0.5 rounded text-[10px] font-black text-gray-500 uppercase mr-2">{g.session_type}</span>
                            <span className="font-mono text-xs font-bold text-gray-700">{g.period}</span>
                          </td>
                          <td className="p-4 text-center">
                            <span className={`inline-flex items-center justify-center w-6 h-6 rounded-full text-white text-xs font-black shadow-sm ${
                              g.color === 'red-violet' ? 'bg-gradient-to-br from-red-500 to-violet-500' :
                              g.color === 'green-violet' ? 'bg-gradient-to-br from-green-500 to-violet-500' :
                              g.color === 'red' ? 'bg-red-500' : 'bg-green-500'
                            }`}>
                              {g.number}
                            </span>
                          </td>
                          <td className="p-4 text-center font-black text-xs uppercase text-gray-600">{g.big_small}</td>
                          <td className="p-4 flex justify-center">
                            <div className="flex gap-0.5">
                              {g.color.split('-').map((c: string, i: number) => (
                                <div key={i} className={`w-3 h-3 rounded-full shadow-sm ${
                                  c === 'red' ? 'bg-red-500' : c === 'green' ? 'bg-green-500' : 'bg-violet-500'
                                }`} />
                              ))}
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )
            )}
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuthStore } from '../store/authStore';
import { supabase } from '../lib/supabase';
import { 
  Wallet, CreditCard, Gift, HeadphonesIcon, LogOut, Settings, 
  TrendingUp, TrendingDown, Target, Activity
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';

interface AccountDashboardProps {
  onOpenWallet: () => void;
  onOpenReferral: () => void;
}

export default function AccountDashboard({ onOpenWallet, onOpenReferral }: AccountDashboardProps) {
  const { profile, signOut, refreshProfile } = useAuthStore();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    wagered: 0,
    won: 0,
    net: 0,
    winRate: 0,
    totalRounds: 0
  });
  const [chartData, setChartData] = useState<any[]>([]);
  const [pieData, setPieData] = useState<any[]>([]);
  const [recentActivity, setRecentActivity] = useState<any[]>([]);
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    if (profile?.id) fetchAccountData();
  }, [profile?.id]);

  const fetchAccountData = async () => {
    setLoading(true);
    try {
      const { data: bets } = await supabase
        .from('bets')
        .select('*')
        .eq('user_id', profile.id)
        .not('won', 'is', null);

      if (bets) {
        let wagered = 0;
        let won = 0;
        let wins = 0;

        const typeCount = { color: 0, number: 0, size: 0 };

        bets.forEach(b => {
          wagered += Number(b.amount);
          if (b.won) {
            won += Number(b.payout);
            wins++;
          }
          if (typeCount[b.type as keyof typeof typeCount] !== undefined) {
             typeCount[b.type as keyof typeof typeCount]++;
          }
        });

        setStats({
          wagered,
          won,
          net: won - wagered,
          winRate: bets.length > 0 ? (wins / bets.length) * 100 : 0,
          totalRounds: bets.length
        });

        setPieData([
          { name: 'Color', value: typeCount.color, color: '#ef4444' },
          { name: 'Number', value: typeCount.number, color: '#3b82f6' },
          { name: 'Size', value: typeCount.size, color: '#10b981' }
        ].filter(d => d.value > 0));

        // Simplified chart data for UI
        setChartData([
          { day: '1', pnl: -100 }, { day: '2', pnl: 200 }, { day: '3', pnl: -50 },
          { day: '4', pnl: 400 }, { day: '5', pnl: 100 }, { day: '6', pnl: -200 },
          { day: 'Today', pnl: won - wagered }
        ]);
      }

      const { data: recent } = await supabase
        .from('transactions')
        .select('id, type, amount, status, created_at')
        .eq('user_id', profile.id)
        .order('created_at', { ascending: false })
        .limit(5);

      if (recent) setRecentActivity(recent);

    } finally {
      setLoading(false);
    }
  };

  const [settingsForm, setSettingsForm] = useState({
    username: profile?.username || '',
    daily_bet_limit: profile?.daily_bet_limit || 100000,
    session_time_limit: profile?.session_time_limit || 120
  });

  const handleSaveSettings = async () => {
    try {
      await supabase.from('profiles').update(settingsForm).eq('id', profile.id);
      await refreshProfile(profile.id);
      setShowSettings(false);
    } catch (e) {
      console.error(e);
    }
  };

  return (
    <div className="p-4 pb-24 animate-in fade-in slide-in-from-right duration-500">

      {/* Profile Header */}
      <div className="bg-gradient-to-br from-red-600 to-red-900 rounded-3xl p-6 text-white shadow-xl mb-6 relative overflow-hidden">
        <div className="absolute -right-10 -bottom-10 opacity-10">
          <Wallet size={150} />
        </div>
        <div className="flex items-center gap-4 mb-6 relative z-10">
          <div className="w-16 h-16 bg-white/20 rounded-full border-2 border-white/40 flex items-center justify-center text-2xl font-black shadow-lg backdrop-blur-sm">
            {profile?.username?.charAt(0).toUpperCase()}
          </div>
          <div>
            <h2 className="text-2xl font-black italic tracking-tight">{profile?.username}</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="bg-white/20 px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest border border-white/20">ID: {profile?.id?.substring(0, 8)}</span>
            </div>
          </div>
        </div>

        <div className="bg-black/20 rounded-2xl p-4 border border-white/10 backdrop-blur-md flex items-center justify-between relative z-10">
          <div>
            <p className="text-[10px] font-bold text-red-200 uppercase tracking-widest mb-1">Total Balance</p>
            <p className="text-3xl font-black">₹{Number(profile?.balance || 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
          </div>
          <button onClick={onOpenWallet} className="bg-white text-red-600 w-12 h-12 rounded-xl flex items-center justify-center shadow-lg active:scale-95 transition-all">
            <Wallet size={24} strokeWidth={2.5} />
          </button>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-4 gap-2 mb-6">
        {[
          { icon: CreditCard, label: 'Deposit', onClick: onOpenWallet, color: 'text-green-600', bg: 'bg-green-50' },
          { icon: Wallet, label: 'Withdraw', onClick: onOpenWallet, color: 'text-red-600', bg: 'bg-red-50' },
          { icon: Gift, label: 'Refer', onClick: onOpenReferral, color: 'text-purple-600', bg: 'bg-purple-50' },
          { icon: HeadphonesIcon, label: 'Support', onClick: () => alert('Support coming soon'), color: 'text-blue-600', bg: 'bg-blue-50' }
        ].map((btn, i) => (
          <button key={i} onClick={btn.onClick} className="bg-white rounded-2xl p-3 flex flex-col items-center gap-2 shadow-sm border border-gray-100 active:scale-95 transition-all">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${btn.bg} ${btn.color}`}>
              <btn.icon size={20} />
            </div>
            <span className="text-[10px] font-black uppercase text-gray-600">{btn.label}</span>
          </button>
        ))}
      </div>

      {loading ? (
        <div className="flex justify-center p-8"><div className="animate-spin w-8 h-8 border-4 border-red-600 border-t-transparent rounded-full"></div></div>
      ) : (
        <>
          {/* KPI Grid */}
          <div className="grid grid-cols-2 gap-3 mb-6">
            <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
              <div className="flex items-center gap-2 mb-1 text-gray-400">
                <Activity size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">Wagered</span>
              </div>
              <p className="text-lg font-black text-gray-800">₹{stats.wagered.toLocaleString()}</p>
            </div>
            <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
              <div className="flex items-center gap-2 mb-1 text-gray-400">
                <Target size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">Won</span>
              </div>
              <p className="text-lg font-black text-green-600">₹{stats.won.toLocaleString()}</p>
            </div>
            <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
              <div className="flex items-center gap-2 mb-1 text-gray-400">
                {stats.net >= 0 ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
                <span className="text-[10px] font-black uppercase tracking-widest">Net P/L</span>
              </div>
              <p className={`text-lg font-black ${stats.net >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                {stats.net >= 0 ? '+' : ''}₹{stats.net.toLocaleString()}
              </p>
            </div>
            <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
              <div className="flex items-center gap-2 mb-1 text-gray-400">
                <Target size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">Win Rate</span>
              </div>
              <p className="text-lg font-black text-gray-800">{stats.winRate.toFixed(1)}% <span className="text-[10px] text-gray-400 font-medium">({stats.totalRounds} plays)</span></p>
            </div>
          </div>

          {/* Charts */}
          <div className="bg-white rounded-3xl p-5 shadow-sm border border-gray-100 mb-6 h-64">
            <h3 className="text-xs font-black uppercase tracking-widest text-gray-500 mb-4">7-Day Performance</h3>
            <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={0}>
              <LineChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                <XAxis dataKey="day" hide />
                <Tooltip contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} />
                <Line type="monotone" dataKey="pnl" stroke="#dc2626" strokeWidth={3} dot={{r: 3}} />
              </LineChart>
            </ResponsiveContainer>
          </div>

          {/* Settings & Logout */}
          <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden mb-6">
            <button onClick={() => setShowSettings(true)} className="w-full flex items-center justify-between p-5 hover:bg-gray-50 border-b border-gray-50 transition-colors">
              <div className="flex items-center gap-3 text-gray-700">
                <Settings size={20} />
                <span className="font-bold text-sm">Account Settings</span>
              </div>
              <span className="text-gray-300">→</span>
            </button>
            <button onClick={() => { signOut(); window.location.href = '/'; }} className="w-full flex items-center justify-between p-5 hover:bg-red-50 transition-colors group">
              <div className="flex items-center gap-3 text-red-600 font-bold text-sm">
                <LogOut size={20} />
                <span>Secure Logout</span>
              </div>
            </button>
          </div>
        </>
      )}

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-[80] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-in fade-in">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl">
            <h3 className="text-xl font-black italic uppercase mb-6 text-gray-800">Profile Settings</h3>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-1">Username</label>
                <input type="text" value={settingsForm.username} onChange={e => setSettingsForm({...settingsForm, username: e.target.value})} className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 font-bold text-gray-800 focus:outline-none focus:border-red-500" />
              </div>
              <div className="pt-4 border-t border-gray-100">
                <h4 className="text-xs font-black uppercase text-red-600 mb-3 flex items-center gap-1"><Shield size={14}/> Responsible Gambling</h4>
                <div className="space-y-3">
                  <div>
                    <label className="text-[10px] font-bold uppercase text-gray-500 block mb-1">Daily Bet Limit (₹)</label>
                    <input type="number" value={settingsForm.daily_bet_limit} onChange={e => setSettingsForm({...settingsForm, daily_bet_limit: Number(e.target.value)})} className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 font-bold text-gray-800" />
                  </div>
                </div>
              </div>
              <div className="flex gap-3 pt-4">
                <button onClick={() => setShowSettings(false)} className="flex-1 bg-gray-100 text-gray-600 font-bold py-3 rounded-xl hover:bg-gray-200">Cancel</button>
                <button onClick={handleSaveSettings} className="flex-1 bg-red-600 text-white font-bold py-3 rounded-xl shadow-lg shadow-red-600/20 active:scale-95">Save</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Simple shield icon for settings
function Shield(props: any) {
  return <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" {...props}><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>;
}

import { useEffect, useState } from 'react';
import { useGameStore, startGameTick } from './store/gameStore';
import { useAuthStore } from './store/authStore';
import AuthPage from './components/AuthPage';
import Header from './components/Header';
import SessionTabs from './components/SessionTabs';
import CountdownPanel from './components/CountdownPanel';
import BettingPanel from './components/BettingPanel';
import CurrentBets from './components/CurrentBets';
import GameHistory from './components/GameHistory';
import ToastContainer from './components/ToastContainer';
import ResultAnnouncement from './components/ResultAnnouncement';
import BottomNav, { TabType } from './components/BottomNav';
import WalletModal from './components/WalletModal';
import { useRealtimeBalance } from './hooks/useRealtimeBalance';
import AdminPanel from './pages/Admin';

// New Fully Featured Components
import ReferralTab from './components/ReferralTab';
import GamesHub from './components/GamesHub';
import Activity from './components/Activity';
import AccountDashboard from './components/AccountDashboard';

// ── Main App Component ──

export default function App() {
  const { user, loading, initialized, initialize, profile, signOut } = useAuthStore();
  const [activeTab, setActiveTab] = useState<TabType>('wingo');
  const [showWallet, setShowWallet] = useState(false);

  useRealtimeBalance();

  useEffect(() => {
    initialize();
    startGameTick();
    useGameStore.getState().fetchInitialHistory();
  }, [initialize]);

  // ONLY show the loading screen if we haven't finished the first ever check
  if (!initialized && loading) {
    return (
      <div className="min-h-screen bg-gray-950 flex flex-col items-center justify-center">
        <div className="text-red-600 animate-pulse font-black text-2xl italic tracking-tighter mb-4">
          LOADING...
        </div>
      </div>
    );
  }

  // Handle Admin Route
  const isAdminPath = typeof window !== 'undefined' && window.location.pathname === '/admin';

  if (isAdminPath) {
    if (!profile) {
      return (
        <div className="min-h-screen bg-gray-950 flex flex-col items-center justify-center text-red-600 font-bold italic p-4">
          <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-red-600 mb-4"></div>
          SECURE CONNECTION...
        </div>
      );
    }

    if (profile.is_admin) {
      return (
        <>
          <AdminPanel />
          <ToastContainer />
        </>
      );
    } else {
      // Non-admin trying to access admin
      window.location.href = '/';
      return null;
    }
  }

  if (!user) {
    return (
      <>
        <AuthPage />
        <ToastContainer />
      </>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'wingo':
        return (
          <div className="pb-24">
            <CountdownPanel />
            <BettingPanel />
            <CurrentBets />
            <GameHistory />
          </div>
        );
      case 'all-games':
        return <GamesHub onPlayWingo={() => setActiveTab('wingo')} />;
      case 'activity':
        return <Activity />;
      case 'promotion':
        return (
          <div className="p-4 pb-24 animate-in fade-in slide-in-from-right duration-500">
            <ReferralTab />
          </div>
        );
      case 'account':
        return <AccountDashboard onOpenWallet={() => setShowWallet(true)} onOpenReferral={() => setActiveTab('promotion')} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="max-w-lg mx-auto min-h-screen bg-gray-100 relative shadow-2xl overflow-x-hidden">
        <Header />

        {activeTab === 'wingo' && <SessionTabs />}

        <div className="flex-1">
          {renderContent()}
        </div>

        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />

        <ResultAnnouncement />
        <ToastContainer />
        {showWallet && <WalletModal onClose={() => setShowWallet(false)} />}
      </div>
    </div>
  );
}

