import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { FileText, ArrowRightLeft, Clock, CheckCircle, XCircle, Activity as ActivityIcon } from 'lucide-react';

export default function Activity() {
  const { profile } = useAuthStore();
  const [activeTab, setActiveTab] = useState<'bets' | 'transactions'>('bets');
  const [loading, setLoading] = useState(true);
  const [bets, setBets] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);

  useEffect(() => {
    if (profile?.id) fetchData();
  }, [profile?.id, activeTab]);

  const fetchData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'bets') {
        const { data } = await supabase
          .from('bets')
          .select('*')
          .eq('user_id', profile.id)
          .order('created_at', { ascending: false })
          .limit(50);
        if (data) setBets(data);
      } else if (activeTab === 'transactions') {
        const { data } = await supabase
          .from('transactions')
          .select('*')
          .eq('user_id', profile.id)
          .order('created_at', { ascending: false })
          .limit(50);
        if (data) setTransactions(data);
      }
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status: string) => {
    if (status === 'completed') return <CheckCircle className="w-3 h-3 text-green-500" />;
    if (status === 'pending') return <ActivityIcon className="w-3 h-3 text-yellow-500 animate-pulse" />;
    return <XCircle className="w-3 h-3 text-red-500" />;
  };

  return (
    <div className="p-4 pb-24 animate-in fade-in slide-in-from-right duration-500">
      <div className="mb-4">
        <h2 className="text-2xl font-black italic uppercase tracking-tight text-gray-800">Activity</h2>
        <p className="text-gray-500 text-xs font-bold uppercase tracking-widest">Track your records</p>
      </div>

      {/* Tabs */}
      <div className="flex bg-white rounded-xl p-1 mb-4 shadow-sm border border-gray-100">
        {[
          { id: 'bets', label: 'My Bets', icon: FileText },
          { id: 'transactions', label: 'Transfers', icon: ArrowRightLeft }
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex-1 flex items-center justify-center gap-1.5 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab.id 
                ? 'bg-red-600 text-white shadow-md' 
                : 'text-gray-400 hover:text-gray-600 hover:bg-gray-50'
            }`}
          >
            <tab.icon className="w-3.5 h-3.5" />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Content Area */}
      <div className="bg-white rounded-3xl border border-gray-100 shadow-sm min-h-[400px] overflow-hidden">
        {loading ? (
          <div className="h-64 flex flex-col items-center justify-center gap-4 text-gray-300">
            <div className="w-8 h-8 border-4 border-gray-200 border-t-red-600 rounded-full animate-spin"></div>
            <p className="text-[10px] font-black uppercase tracking-widest animate-pulse">Syncing Database...</p>
          </div>
        ) : (
          <div className="divide-y divide-gray-50">

            {/* BETS TAB */}
            {activeTab === 'bets' && (
              bets.length === 0 ? (
                <div className="p-10 text-center text-gray-400">
                  <FileText className="w-12 h-12 mx-auto mb-2 opacity-20" />
                  <p className="text-xs font-bold uppercase tracking-widest">No bets found</p>
                </div>
              ) : (
                bets.map((bet) => (
                  <div key={bet.id} className="p-4 hover:bg-gray-50 transition-colors">
                    <div className="flex justify-between items-start mb-2">
                      <div>
                        <span className="bg-gray-100 text-gray-600 text-[10px] font-black uppercase px-2 py-0.5 rounded-md border border-gray-200 mr-2">
                          {bet.session_type}
                        </span>
                        <span className="text-xs font-bold text-gray-800 font-mono tracking-tight">{bet.period}</span>
                      </div>
                      <span className="text-[9px] font-bold text-gray-400 uppercase tracking-tighter flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {new Date(bet.created_at).toLocaleTimeString()}
                      </span>
                    </div>
                    <div className="flex items-center justify-between mt-3">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-gray-50 flex flex-col items-center justify-center border border-gray-100">
                          <span className="text-[8px] font-black uppercase text-gray-400 tracking-tighter">Bet</span>
                          <span className="text-sm font-black capitalize text-gray-800">{bet.value}</span>
                        </div>
                        <div>
                          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Amount</p>
                          <p className="text-sm font-black text-gray-800">₹{bet.amount}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-0.5">Result</p>
                        {bet.won === null ? (
                          <span className="text-sm font-black text-yellow-500 animate-pulse">Pending</span>
                        ) : bet.won ? (
                          <span className="text-sm font-black text-green-600">+ ₹{bet.payout}</span>
                        ) : (
                          <span className="text-sm font-black text-red-500">- ₹{bet.amount}</span>
                        )}
                      </div>
                    </div>
                  </div>
                ))
              )
            )}

            {/* TRANSACTIONS TAB */}
            {activeTab === 'transactions' && (
              transactions.length === 0 ? (
                <div className="p-10 text-center text-gray-400">
                  <ArrowRightLeft className="w-12 h-12 mx-auto mb-2 opacity-20" />
                  <p className="text-xs font-bold uppercase tracking-widest">No transactions</p>
                </div>
              ) : (
                transactions.map((tx) => (
                  <div key={tx.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                    <div className="flex items-center gap-4">
                      <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-lg ${
                        tx.type === 'deposit' ? 'bg-green-50 text-green-600' :
                        tx.type === 'withdrawal' ? 'bg-red-50 text-red-600' :
                        tx.type === 'win' ? 'bg-yellow-50 text-yellow-600' :
                        'bg-gray-100 text-gray-600'
                      }`}>
                        {tx.type === 'deposit' ? '↓' : tx.type === 'withdrawal' ? '↑' : tx.type === 'win' ? '★' : '−'}
                      </div>
                      <div>
                        <p className="text-sm font-black capitalize italic text-gray-800">{tx.type}</p>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter mt-0.5">
                          {new Date(tx.created_at).toLocaleString()}
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className={`text-base font-black ${tx.type === 'deposit' || tx.type === 'win' ? 'text-green-600' : 'text-gray-800'}`}>
                        {tx.type === 'deposit' || tx.type === 'win' ? '+' : '-'}₹{Number(tx.amount).toLocaleString()}
                      </p>
                      <div className="flex items-center justify-end gap-1 mt-1">
                        {getStatusIcon(tx.status)}
                        <span className={`text-[9px] font-black uppercase tracking-widest ${
                          tx.status === 'completed' ? 'text-green-500' : 
                          tx.status === 'pending' ? 'text-yellow-500' : 'text-red-500'
                        }`}>
                          {tx.status}
                        </span>
                      </div>
                    </div>
                  </div>
                ))
              )
            )}
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { supabase } from '../lib/supabase';
import { 
  ChevronLeft, ChevronRight, Search, Calendar, 
  Filter, X, Download, Loader2 
} from 'lucide-react';
import { cn } from '../utils/cn';

interface PaginatedTableProps {
  tableName: string;
  queryModifier?: (query: any) => any;
  columns: { key: string; label: string; render?: (row: any) => React.ReactNode }[];
  pageSize?: number;
  searchPlaceholder?: string;
  searchFields?: string[];
  dateField?: string;
  emptyMessage?: string;
  onDataLoaded?: (data: any[]) => void;
}

export default function PaginatedTable({
  tableName,
  queryModifier,
  columns,
  pageSize = 10,
  searchPlaceholder = "Search...",
  searchFields = [],
  dateField = "created_at",
  emptyMessage = "No records found",
  onDataLoaded
}: PaginatedTableProps) {
  const [data, setData] = useState<any[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [currentPage, setCurrentPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState<'all' | 'today' | '7d' | '30d' | 'custom'>('30d');
  const [customRange, setCustomRange] = useState({ from: '', to: '' });
  const [showFilters, setShowFilters] = useState(false);

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      let query = supabase
        .from(tableName)
        .select('*', { count: 'exact' });

      // Apply query modifier (e.g., user_id filter)
      if (queryModifier) {
        query = queryModifier(query);
      }

      // Apply Search
      if (search && searchFields.length > 0) {
        const searchConditions = searchFields.map(field => `${field}.ilike.%${search}%`).join(',');
        query = query.or(searchConditions);
      }

      // Apply Date Filter
      const now = new Date();
      if (dateFilter === 'today') {
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
        query = query.gte(dateField, today);
      } else if (dateFilter === '7d') {
        const last7d = new Date(now.setDate(now.getDate() - 7)).toISOString();
        query = query.gte(dateField, last7d);
      } else if (dateFilter === '30d') {
        const last30d = new Date(now.setDate(now.getDate() - 30)).toISOString();
        query = query.gte(dateField, last30d);
      } else if (dateFilter === 'custom' && customRange.from && customRange.to) {
        query = query.gte(dateField, customRange.from).lte(dateField, customRange.to + 'T23:59:59');
      }

      // Pagination
      const from = (currentPage - 1) * pageSize;
      const to = from + pageSize - 1;

      query = query
        .order(dateField, { ascending: false })
        .range(from, to);

      const { data: result, count, error } = await query;

      if (error) throw error;

      setData(result || []);
      setTotalCount(count || 0);
      if (onDataLoaded) onDataLoaded(result || []);
    } catch (err) {
      console.error(`Error fetching ${tableName}:`, err);
    } finally {
      setLoading(false);
    }
  }, [tableName, queryModifier, currentPage, pageSize, search, dateFilter, customRange, searchFields, dateField, onDataLoaded]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const totalPages = Math.ceil(totalCount / pageSize);

  const handlePageChange = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setCurrentPage(1);
    fetchData();
  };

  const clearFilters = () => {
    setSearch('');
    setDateFilter('all');
    setCustomRange({ from: '', to: '' });
    setCurrentPage(1);
  };

  const exportToCSV = () => {
    if (data.length === 0) return;
    const headers = columns.map(col => col.label).join(',');
    const rows = data.map(row => 
      columns.map(col => {
        const val = row[col.key];
        return typeof val === 'object' ? JSON.stringify(val) : `"${val}"`;
      }).join(',')
    ).join('\n');

    const csvContent = "data:text/csv;charset=utf-8," + headers + "\n" + rows;
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${tableName}_export.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-4">
      {/* Header Controls */}
      <div className="flex flex-col md:flex-row gap-3">
        <form onSubmit={handleSearch} className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder={searchPlaceholder}
            className="w-full bg-white border border-gray-200 rounded-xl py-2.5 pl-10 pr-4 text-sm focus:outline-none focus:border-red-500 transition-colors"
          />
        </form>

        <div className="flex gap-2">
          <button 
            onClick={() => setShowFilters(!showFilters)}
            className={cn(
              "flex items-center gap-2 px-4 py-2.5 rounded-xl text-xs font-black uppercase transition-all border",
              showFilters || dateFilter !== 'all' ? "bg-red-50 border-red-200 text-red-600" : "bg-white border-gray-200 text-gray-600"
            )}
          >
            <Filter size={14} />
            Filter
          </button>
          <button 
            onClick={exportToCSV}
            className="flex items-center gap-2 px-4 py-2.5 rounded-xl bg-white border border-gray-200 text-gray-600 text-xs font-black uppercase hover:bg-gray-50 transition-all"
          >
            <Download size={14} />
            Export
          </button>
        </div>
      </div>

      {/* Filter Panel */}
      {showFilters && (
        <div className="bg-gray-50 border border-gray-200 rounded-2xl p-4 space-y-4 animate-in fade-in slide-in-from-top-2">
          <div className="flex flex-wrap gap-2">
            {[
              { id: 'all', label: 'All Time' },
              { id: 'today', label: 'Today' },
              { id: '7d', label: 'Last 7 Days' },
              { id: '30d', label: 'Last 30 Days' },
              { id: 'custom', label: 'Custom Range' }
            ].map(btn => (
              <button
                key={btn.id}
                onClick={() => setDateFilter(btn.id as any)}
                className={cn(
                  "px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all",
                  dateFilter === btn.id ? "bg-red-600 text-white" : "bg-white border border-gray-200 text-gray-500"
                )}
              >
                {btn.label}
              </button>
            ))}
          </div>

          {dateFilter === 'custom' && (
            <div className="flex items-center gap-2">
              <input 
                type="date" 
                value={customRange.from}
                onChange={e => setCustomRange({...customRange, from: e.target.value})}
                className="bg-white border border-gray-200 rounded-lg p-2 text-xs font-bold" 
              />
              <span className="text-gray-400 text-xs">to</span>
              <input 
                type="date" 
                value={customRange.to}
                onChange={e => setCustomRange({...customRange, to: e.target.value})}
                className="bg-white border border-gray-200 rounded-lg p-2 text-xs font-bold" 
              />
            </div>
          )}

          <div className="flex justify-between items-center pt-2 border-t border-gray-200">
            <button onClick={clearFilters} className="text-[10px] font-black uppercase text-gray-400 hover:text-red-600 transition-colors">Clear All</button>
            <button 
              onClick={() => { setShowFilters(false); setCurrentPage(1); fetchData(); }}
              className="bg-gray-900 text-white px-4 py-1.5 rounded-lg text-[10px] font-black uppercase"
            >
              Apply Filters
            </button>
          </div>
        </div>
      )}

      {/* Table Content */}
      <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden min-h-[300px] relative">
        {loading && (
          <div className="absolute inset-0 bg-white/60 backdrop-blur-[1px] z-10 flex items-center justify-center">
            <Loader2 className="w-8 h-8 text-red-600 animate-spin" />
          </div>
        )}

        {data.length === 0 && !loading ? (
          <div className="flex flex-col items-center justify-center h-64 text-gray-400 opacity-50">
            <Filter size={48} className="mb-4" />
            <p className="font-bold uppercase text-xs tracking-widest">{emptyMessage}</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead className="bg-gray-50/50 border-b border-gray-100">
                <tr>
                  {columns.map(col => (
                    <th key={col.key} className="p-4 text-[10px] font-black uppercase text-gray-400 tracking-wider">
                      {col.label}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {data.map((row, idx) => (
                  <tr key={row.id || idx} className="hover:bg-gray-50/50 transition-colors">
                    {columns.map(col => (
                      <td key={col.key} className="p-4">
                        {col.render ? col.render(row) : row[col.key]}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pagination Bar */}
      {totalPages > 0 && (
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 px-2 py-4 border-t border-gray-100">
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            Showing <span className="text-gray-900">{(currentPage-1)*pageSize + 1}</span> to <span className="text-gray-900">{Math.min(currentPage*pageSize, totalCount)}</span> of <span className="text-gray-900">{totalCount}</span> records
          </p>

          <div className="flex items-center gap-1">
            <button
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="p-2 rounded-xl border border-gray-200 text-gray-400 disabled:opacity-30 hover:bg-gray-50 transition-all"
            >
              <ChevronLeft size={16} />
            </button>

            <div className="flex items-center gap-1">
              {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                let pageNum = currentPage;
                if (currentPage <= 3) pageNum = i + 1;
                else if (currentPage >= totalPages - 2) pageNum = totalPages - 4 + i;
                else pageNum = currentPage - 2 + i;

                if (pageNum < 1 || pageNum > totalPages) return null;

                return (
                  <button
                    key={pageNum}
                    onClick={() => handlePageChange(pageNum)}
                    className={cn(
                      "w-8 h-8 rounded-xl text-xs font-black transition-all",
                      currentPage === pageNum ? "bg-red-600 text-white shadow-lg shadow-red-600/20" : "bg-white border border-gray-200 text-gray-600 hover:bg-gray-50"
                    )}
                  >
                    {pageNum}
                  </button>
                );
              })}
            </div>

            <button
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="p-2 rounded-xl border border-gray-200 text-gray-400 disabled:opacity-30 hover:bg-gray-50 transition-all"
            >
              <ChevronRight size={16} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { useAuthStore } from '../store/authStore';
import { FileText, ArrowRightLeft, Clock, CheckCircle, XCircle, Activity as ActivityIcon } from 'lucide-react';
import PaginatedTable from './PaginatedTable';

export default function Activity() {
  const { profile } = useAuthStore();
  const [activeTab, setActiveTab] = useState<'bets' | 'transactions'>('bets');

  const getStatusIcon = (status: string) => {
    if (status === 'completed') return <CheckCircle className="w-3 h-3 text-green-500" />;
    if (status === 'pending') return <ActivityIcon className="w-3 h-3 text-yellow-500 animate-pulse" />;
    return <XCircle className="w-3 h-3 text-red-500" />;
  };

  const betColumns = [
    { 
      key: 'period', 
      label: 'Period', 
      render: (row: any) => (
        <div>
          <span className="bg-gray-100 text-gray-600 text-[8px] font-black uppercase px-1.5 py-0.5 rounded mr-1.5 border border-gray-200">
            {row.session_type}
          </span>
          <span className="text-[10px] font-bold text-gray-800 font-mono">{row.period}</span>
        </div>
      )
    },
    { 
      key: 'value', 
      label: 'Bet', 
      render: (row: any) => <span className="capitalize font-black text-gray-700">{row.value}</span>
    },
    { 
      key: 'amount', 
      label: 'Amount', 
      render: (row: any) => <span className="font-black text-gray-900">₹{row.amount}</span>
    },
    { 
      key: 'payout', 
      label: 'Result', 
      render: (row: any) => (
        <div className="text-right">
          {row.won === null ? (
            <span className="text-[10px] font-black text-yellow-500 animate-pulse uppercase">Pending</span>
          ) : row.won ? (
            <span className="text-[10px] font-black text-green-600 uppercase">+ ₹{row.payout}</span>
          ) : (
            <span className="text-[10px] font-black text-red-500 uppercase">- ₹{row.amount}</span>
          )}
        </div>
      )
    }
  ];

  const transactionColumns = [
    { 
      key: 'type', 
      label: 'Type', 
      render: (row: any) => (
        <div className="flex items-center gap-2">
          <div className={`w-6 h-6 rounded-lg flex items-center justify-center text-[10px] font-black ${
            row.type === 'deposit' ? 'bg-green-50 text-green-600' :
            row.type === 'withdrawal' ? 'bg-red-50 text-red-600' :
            row.type === 'win' ? 'bg-yellow-50 text-yellow-600' :
            'bg-gray-100 text-gray-600'
          }`}>
            {row.type === 'deposit' ? '↓' : row.type === 'withdrawal' ? '↑' : row.type === 'win' ? '★' : '−'}
          </div>
          <span className="capitalize font-black italic text-gray-800 text-xs">{row.type}</span>
        </div>
      )
    },
    { 
      key: 'amount', 
      label: 'Amount', 
      render: (row: any) => (
        <span className={Number(row.amount) > 0 ? 'text-green-600 font-black' : 'text-gray-800 font-black'}>
          ₹{Math.abs(Number(row.amount)).toLocaleString()}
        </span>
      )
    },
    { 
      key: 'status', 
      label: 'Status', 
      render: (row: any) => (
        <div className="flex items-center gap-1">
          {getStatusIcon(row.status)}
          <span className={`text-[8px] font-black uppercase tracking-widest ${
            row.status === 'completed' ? 'text-green-500' : 
            row.status === 'pending' ? 'text-yellow-500' : 'text-red-500'
          }`}>
            {row.status}
          </span>
        </div>
      )
    },
    {
      key: 'created_at',
      label: 'Date',
      render: (row: any) => <span className="text-[9px] font-bold text-gray-400">{new Date(row.created_at).toLocaleDateString()}</span>
    }
  ];

  return (
    <div className="p-4 pb-24 animate-in fade-in slide-in-from-right duration-500">
      <div className="mb-4">
        <h2 className="text-2xl font-black italic uppercase tracking-tight text-gray-800">Activity</h2>
        <p className="text-gray-500 text-xs font-bold uppercase tracking-widest">Track your records</p>
      </div>

      <div className="flex bg-white rounded-xl p-1 mb-6 shadow-sm border border-gray-100">
        {[
          { id: 'bets', label: 'My Bets', icon: FileText },
          { id: 'transactions', label: 'Transfers', icon: ArrowRightLeft }
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex-1 flex items-center justify-center gap-1.5 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab.id 
                ? 'bg-red-600 text-white shadow-md' 
                : 'text-gray-400 hover:text-gray-600 hover:bg-gray-50'
            }`}
          >
            <tab.icon className="w-3.5 h-3.5" />
            {tab.label}
          </button>
        ))}
      </div>

      {activeTab === 'bets' ? (
        <PaginatedTable
          key="bets-table"
          tableName="bets"
          queryModifier={(q) => q.eq('user_id', profile?.id)}
          columns={betColumns}
          searchFields={['period', 'value', 'session_type']}
          searchPlaceholder="Search period or type..."
          pageSize={10}
          emptyMessage="No betting records found"
        />
      ) : (
        <PaginatedTable
          key="tx-table"
          tableName="transactions"
          queryModifier={(q) => q.eq('user_id', profile?.id)}
          columns={transactionColumns}
          searchFields={['type', 'status', 'utr']}
          searchPlaceholder="Search type or status..."
          pageSize={10}
          emptyMessage="No transaction records found"
        />
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';
import { 
  LayoutDashboard, Users, Activity, History, CreditCard, Settings, LogOut, CheckCircle, XCircle, Wallet, Share2, ClipboardList
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import PaginatedTable from '../components/PaginatedTable';

export default function AdminPanel() {
  const { profile, signOut } = useAuthStore();
  const { addToast } = useGameStore();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [appSettings, setAppSettings] = useState({ upi_id: '', referral_deposit_bonus_percent: 10, referral_bet_loss_bonus_percent: 5 });
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalBetsToday: 0,
    houseProfit: 0,
    totalRevenue: 0,
    totalReferralPaid: 0
  });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (profile?.is_admin && activeTab === 'dashboard') {
      fetchDashboardStats();
    }
    if (profile?.is_admin && activeTab === 'settings') {
      fetchSettings();
    }
  }, [profile, activeTab]);

  const fetchDashboardStats = async () => {
    setLoading(true);
    try {
      const { count: userCount } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
      const { data: txs } = await supabase.from('transactions').select('*').gte('created_at', new Date(Date.now() - 86400000).toISOString());
      const { data: allEarnings } = await supabase.from('referral_earnings').select('amount');

      let profit = 0;
      let revenue = 0;
      if (txs) {
        txs.forEach(tx => {
          if (tx.type === 'loss') profit += Number(tx.amount);
          if (tx.type === 'win') profit -= Number(tx.amount);
          if (tx.type === 'deposit' && tx.status === 'completed') revenue += Number(tx.amount);
        });
      }

      setStats({
        totalUsers: userCount || 0,
        totalBetsToday: txs?.filter(t => t.type === 'bet').length || 0,
        houseProfit: profit,
        totalRevenue: revenue,
        totalReferralPaid: allEarnings?.reduce((sum, e) => sum + Number(e.amount), 0) || 0
      });
    } finally {
      setLoading(false);
    }
  };

  const fetchSettings = async () => {
    const { data } = await supabase.from('app_settings').select('*').eq('id', 1).single();
    if (data) setAppSettings({ 
      upi_id: data.upi_id || '',
      referral_deposit_bonus_percent: data.referral_deposit_bonus_percent,
      referral_bet_loss_bonus_percent: data.referral_bet_loss_bonus_percent
    });
  };

  const handleProcessWithdrawal = async (txId: string, approve: boolean) => {
    try {
      const { error } = await supabase.rpc('admin_process_withdrawal', { p_transaction_id: txId, p_approve: approve });
      if (error) throw error;
      addToast('success', `Withdrawal ${approve ? 'approved' : 'rejected'}`);
      // Tables will refresh automatically due to key changes or re-mount if needed
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleProcessDeposit = async (txId: string, approve: boolean) => {
    const reason = approve ? '' : prompt('Reason for rejection:');
    if (!approve && reason === null) return;
    try {
      const { error } = await supabase.rpc('admin_process_deposit', { p_transaction_id: txId, p_approve: approve, p_reason: reason || null });
      if (error) throw error;
      addToast('success', `Deposit ${approve ? 'approved' : 'rejected'}`);
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleSaveSettings = async () => {
    try {
      const { error } = await supabase.from('app_settings').update(appSettings).eq('id', 1);
      if (error) throw error;
      addToast('success', 'Settings saved');
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleEditBalance = async (userId: string, currentBalance: number) => {
    const newBal = prompt('Enter new balance:', currentBalance.toString());
    if (!newBal) return;
    try {
      const { error } = await supabase.rpc('admin_edit_balance', { p_target_user_id: userId, p_new_balance: Number(newBal), p_reason: 'Admin Adjustment' });
      if (error) throw error;
      addToast('success', 'Balance updated');
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleForceResult = async (sessionType: string) => {
    const num = prompt(`Force result for ${sessionType}\nNumber (0-9):`);
    if (num === null) return;
    const parsedNum = parseInt(num);
    if (isNaN(parsedNum) || parsedNum < 0 || parsedNum > 9) { addToast('error', 'Invalid number'); return; }
    const color = (parsedNum === 0 || parsedNum === 5) ? (parsedNum === 0 ? 'red-violet' : 'green-violet') : ([1,3,7,9].includes(parsedNum) ? 'green' : 'red');
    const bsChoice = prompt(`Calculated: ${parsedNum >= 5 ? 'Big' : 'Small'}\nEnter B/S to override:`);
    let bigSmall = parsedNum >= 5 ? 'Big' : 'Small';
    if (bsChoice?.toUpperCase() === 'B') bigSmall = 'Big';
    if (bsChoice?.toUpperCase() === 'S') bigSmall = 'Small';

    const sessionData = useGameStore.getState().sessions[sessionType as any];
    try {
      const { error } = await supabase.rpc('admin_force_result', { 
        p_session_type: sessionType, 
        p_period: sessionData.period, 
        p_number: parsedNum, 
        p_color: color, 
        p_big_small: bigSmall 
      });
      if (error) throw error;
      addToast('success', `Forced next result: ${parsedNum} (${bigSmall})`);
    } catch (err: any) { addToast('error', err.message); }
  };

  const chartData = [{ name: 'Sun', profit: stats.houseProfit }];

  if (!profile?.is_admin) return null;

  return (
    <div className="min-h-screen bg-gray-50 flex text-gray-900 font-sans">
      {/* Sidebar */}
      <div className="w-64 bg-gray-900 text-white flex flex-col fixed h-full shadow-2xl z-20">
        <div className="p-6 flex items-center gap-3 border-b border-gray-800">
          <div className="bg-red-600 text-white font-black text-xl w-10 h-10 flex items-center justify-center rounded-xl shadow-lg">66</div>
          <span className="font-bold text-xl tracking-tight uppercase italic">Admin</span>
        </div>

        <nav className="flex-1 py-6 px-4 space-y-2 overflow-y-auto">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'monitor', icon: Activity, label: 'Games Monitor' },
            { id: 'rounds', icon: History, label: 'Game Rounds' },
            { id: 'users', icon: Users, label: 'User Control' },
            { id: 'deposits', icon: Wallet, label: 'Pending Deposits' },
            { id: 'referrals', icon: Share2, label: 'Referrals' },
            { id: 'transactions', icon: CreditCard, label: 'Financials' },
            { id: 'settings', icon: Settings, label: 'Settings' },
          ].map((item) => (
