    </div>
  );
}

import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';
import { Copy, Share2, Users, Wallet, TrendingUp, HelpCircle, History } from 'lucide-react';
import PaginatedTable from './PaginatedTable';

export default function ReferralTab() {
  const { profile } = useAuthStore();
  const { addToast } = useGameStore();
  const [activeTab, setActiveTab] = useState<'subordinates' | 'earnings'>('subordinates');
  const [stats, setStats] = useState({
    totalReferred: 0,
    totalEarnings: 0,
    thisMonth: 0
  });

  useEffect(() => {
    if (profile?.id) fetchReferralStats();
  }, [profile]);

  const fetchReferralStats = async () => {
    // 1. Fetch referral count
    const { count } = await supabase
      .from('profiles')
      .select('*', { count: 'exact', head: true })
      .eq('referred_by', profile.id);

    // 2. Fetch total earnings
    const { data: earnings } = await supabase
      .from('referral_earnings')
      .select('amount, created_at')
      .eq('referrer_id', profile.id);

    const totalEarned = earnings?.reduce((sum, e) => sum + Number(e.amount), 0) || 0;

    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
    const monthEarned = earnings
      ?.filter(e => e.created_at >= firstDay)
      .reduce((sum, e) => sum + Number(e.amount), 0) || 0;

    setStats({
      totalReferred: count || 0,
      totalEarnings: totalEarned,
      thisMonth: monthEarned
    });
  };

  const referralLink = `${window.location.origin}/register?ref=${profile?.referral_code}`;

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    addToast('success', `${label} copied!`);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Invite Card */}
      <div className="bg-gradient-to-br from-red-600 to-red-800 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10"><Share2 size={120} /></div>
        <h3 className="text-2xl font-black italic mb-1 uppercase tracking-tight">Refer & Earn</h3>
        <p className="text-red-100 text-xs font-medium mb-6 opacity-80 uppercase tracking-widest">Share with friends and earn commission</p>

        <div className="space-y-4">
          <div className="bg-white/10 backdrop-blur-md border border-white/20 rounded-2xl p-4">
            <p className="text-[10px] font-bold uppercase tracking-widest text-red-200 mb-2">My Referral Code</p>
            <div className="flex items-center justify-between">
              <span className="text-2xl font-black tracking-[0.3em] font-mono">{profile?.referral_code || '-------'}</span>
              <button onClick={() => copyToClipboard(profile?.referral_code || '', 'Code')} className="bg-white text-red-600 px-4 py-2 rounded-xl font-black text-xs uppercase active:scale-95 transition-all">Copy</button>
            </div>
          </div>
          <div className="bg-black/20 rounded-2xl p-4 flex items-center justify-between group">
            <div className="overflow-hidden mr-4">
              <p className="text-[10px] font-bold uppercase text-red-300 mb-1">Invite Link</p>
              <p className="text-[11px] font-mono opacity-60 truncate">{referralLink}</p>
            </div>
            <button onClick={() => copyToClipboard(referralLink, 'Link')} className="p-2 hover:bg-white/10 rounded-full transition-colors"><Copy size={18} /></button>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-3 gap-3">
        {[
          { label: 'Invited', value: stats.totalReferred, icon: Users, color: 'text-blue-500', bg: 'bg-blue-500/10' },
          { label: 'Total Earning', value: `₹${stats.totalEarnings.toFixed(0)}`, icon: Wallet, color: 'text-green-500', bg: 'bg-green-500/10' },
          { label: 'This Month', value: `₹${stats.thisMonth.toFixed(0)}`, icon: TrendingUp, color: 'text-amber-500', bg: 'bg-amber-500/10' },
        ].map((s, i) => (
          <div key={i} className="bg-white border border-gray-100 rounded-2xl p-3 text-center shadow-sm">
            <div className={`w-8 h-8 ${s.bg} ${s.color} rounded-lg flex items-center justify-center mx-auto mb-2`}><s.icon size={16} /></div>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter mb-0.5">{s.label}</p>
            <p className="text-sm font-black text-gray-800">{s.value}</p>
          </div>
        ))}
      </div>

      <div className="flex bg-white rounded-xl p-1 shadow-sm border border-gray-100">
        <button onClick={() => setActiveTab('subordinates')} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${activeTab === 'subordinates' ? 'bg-red-600 text-white shadow-md' : 'text-gray-400'}`}>Subordinates</button>
        <button onClick={() => setActiveTab('earnings')} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${activeTab === 'earnings' ? 'bg-red-600 text-white shadow-md' : 'text-gray-400'}`}>Earnings</button>
      </div>

      {activeTab === 'subordinates' ? (
        <PaginatedTable
          tableName="profiles"
          queryModifier={(q) => q.eq('referred_by', profile?.id)}
          pageSize={10}
          emptyMessage="No subordinates yet"
          columns={[
            { key: 'username', label: 'User', render: (r) => <span className="font-bold text-gray-800 uppercase italic text-xs">{r.username.substring(0,3)}****{r.username.slice(-2)}</span> },
            { key: 'created_at', label: 'Joined', render: (r) => <span className="text-[9px] font-bold text-gray-400">{new Date(r.created_at).toLocaleDateString()}</span> },
            { key: 'status', label: 'Status', render: () => <span className="text-[8px] font-black text-green-600 bg-green-50 px-1.5 py-0.5 rounded uppercase">Active</span> }
          ]}
        />
      ) : (
        <PaginatedTable
          tableName="referral_earnings"
          queryModifier={(q) => q.eq('referrer_id', profile?.id)}
          pageSize={10}
          emptyMessage="No earnings yet"
          columns={[
            { key: 'from_type', label: 'Type', render: (r) => <span className="uppercase font-black text-[9px] italic text-gray-600">{r.from_type}</span> },
            { key: 'amount', label: 'Amount', render: (r) => <span className="text-green-600 font-black text-xs">+ ₹{r.amount}</span> },
            { key: 'created_at', label: 'Time', render: (r) => <span className="text-[9px] font-bold text-gray-400">{new Date(r.created_at).toLocaleDateString()}</span> }
          ]}
        />
      )}

      {/* How it works */}
      <div className="bg-white rounded-3xl border border-gray-100 p-6 shadow-sm">
        <div className="flex items-center gap-2 mb-4"><HelpCircle size={18} className="text-red-600" /><h4 className="font-black uppercase italic text-sm text-gray-800">How it works?</h4></div>
        <div className="space-y-4">
          {[
            { step: '01', title: 'Invite Friends', desc: 'Share your referral link or code with your friends.' },
            { step: '02', title: 'Friends Register', desc: 'When they sign up using your code, they become your subordinate.' },
            { step: '03', title: 'Earn Commission', desc: 'Get 10% bonus on their deposits & 5% on their game losses!' },
          ].map((s, i) => (
            <div key={i} className="flex gap-4"><span className="text-xl font-black text-red-100 leading-none">{s.step}</span><div><p className="text-xs font-bold text-gray-800 mb-0.5">{s.title}</p><p className="text-[10px] text-gray-400 font-medium leading-relaxed">{s.desc}</p></div></div>
          ))}
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuthStore } from '../store/authStore';
import { supabase } from '../lib/supabase';
import { 
  Wallet, CreditCard, Gift, HeadphonesIcon, LogOut, Settings, 
  TrendingUp, TrendingDown, Target, Activity, Clock
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import PaginatedTable from './PaginatedTable';

interface AccountDashboardProps {
  onOpenWallet: () => void;
  onOpenReferral: () => void;
}

export default function AccountDashboard({ onOpenWallet, onOpenReferral }: AccountDashboardProps) {
  const { profile, signOut, refreshProfile } = useAuthStore();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ wagered: 0, won: 0, net: 0, winRate: 0, totalRounds: 0 });
  const [chartData, setChartData] = useState<any[]>([]);
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    if (profile?.id) fetchAccountData();
  }, [profile?.id]);

  const fetchAccountData = async () => {
    setLoading(true);
    try {
      const { data: bets } = await supabase
        .from('bets')
        .select('*')
        .eq('user_id', profile.id)
        .not('won', 'is', null);

      if (bets) {
        let wagered = 0, won = 0, wins = 0;
        bets.forEach(b => {
          wagered += Number(b.amount);
          if (b.won) { won += Number(b.payout); wins++; }
        });
        setStats({ wagered, won, net: won - wagered, winRate: bets.length > 0 ? (wins / bets.length) * 100 : 0, totalRounds: bets.length });
        setChartData([{ day: '1', pnl: -100 }, { day: '2', pnl: 200 }, { day: 'Today', pnl: won - wagered }]);
      }
    } finally {
      setLoading(false);
    }
  };

  const [settingsForm, setSettingsForm] = useState({
    username: profile?.username || '',
    daily_bet_limit: profile?.daily_bet_limit || 100000,
  });

  const handleSaveSettings = async () => {
    try {
      await supabase.from('profiles').update(settingsForm).eq('id', profile.id);
      await refreshProfile(profile.id);
      setShowSettings(false);
    } catch (e) { console.error(e); }
  };

  return (
    <div className="p-4 pb-24 animate-in fade-in slide-in-from-right duration-500">
      {/* Profile Header */}
      <div className="bg-gradient-to-br from-red-600 to-red-900 rounded-3xl p-6 text-white shadow-xl mb-6 relative overflow-hidden">
        <div className="absolute -right-10 -bottom-10 opacity-10"><Wallet size={150} /></div>
        <div className="flex items-center gap-4 mb-6 relative z-10">
          <div className="w-16 h-16 bg-white/20 rounded-full border-2 border-white/40 flex items-center justify-center text-2xl font-black shadow-lg backdrop-blur-sm">
            {profile?.username?.charAt(0).toUpperCase()}
          </div>
          <div>
            <h2 className="text-2xl font-black italic tracking-tight">{profile?.username}</h2>
            <span className="bg-white/20 px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest border border-white/20">ID: {profile?.id?.substring(0, 8)}</span>
          </div>
        </div>
        <div className="bg-black/20 rounded-2xl p-4 border border-white/10 backdrop-blur-md flex items-center justify-between relative z-10">
          <div><p className="text-[10px] font-bold text-red-200 uppercase mb-1">Total Balance</p><p className="text-3xl font-black">₹{Number(profile?.balance || 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p></div>
          <button onClick={onOpenWallet} className="bg-white text-red-600 w-12 h-12 rounded-xl flex items-center justify-center shadow-lg"><Wallet size={24} strokeWidth={2.5} /></button>
        </div>
      </div>

      <div className="grid grid-cols-4 gap-2 mb-6">
        {[
          { icon: CreditCard, label: 'Deposit', onClick: onOpenWallet, color: 'text-green-600', bg: 'bg-green-50' },
          { icon: Wallet, label: 'Withdraw', onClick: onOpenWallet, color: 'text-red-600', bg: 'bg-red-50' },
          { icon: Gift, label: 'Refer', onClick: onOpenReferral, color: 'text-purple-600', bg: 'bg-purple-50' },
          { icon: HeadphonesIcon, label: 'Support', onClick: () => alert('Support coming soon'), color: 'text-blue-600', bg: 'bg-blue-50' }
        ].map((btn, i) => (
          <button key={i} onClick={btn.onClick} className="bg-white rounded-2xl p-3 flex flex-col items-center gap-2 shadow-sm border border-gray-100 active:scale-95 transition-all">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center ${btn.bg} ${btn.color}`}><btn.icon size={20} /></div>
            <span className="text-[10px] font-black uppercase text-gray-600">{btn.label}</span>
          </button>
        ))}
      </div>

      <div className="grid grid-cols-2 gap-3 mb-6">
        {[
          { label: 'Wagered', value: `₹${stats.wagered.toLocaleString()}`, icon: Activity, color: 'text-gray-400' },
          { label: 'Won', value: `₹${stats.won.toLocaleString()}`, icon: Target, color: 'text-green-600' },
          { label: 'Net P/L', value: `${stats.net >= 0 ? '+' : ''}₹${stats.net.toLocaleString()}`, icon: TrendingUp, color: stats.net >= 0 ? 'text-green-600' : 'text-red-600' },
          { label: 'Win Rate', value: `${stats.winRate.toFixed(1)}%`, icon: Target, color: 'text-gray-800' }
        ].map((s, i) => (
          <div key={i} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
            <div className="flex items-center gap-2 mb-1 text-gray-400"><s.icon size={14} /><span className="text-[10px] font-black uppercase tracking-widest">{s.label}</span></div>
            <p className={`text-lg font-black ${s.color}`}>{s.value}</p>
          </div>
        ))}
      </div>

      <div className="mb-6">
        <h3 className="text-sm font-black uppercase tracking-tight text-gray-800 mb-4 flex items-center gap-2 italic"><Clock size={18} className="text-red-600" /> Recent Transactions</h3>
        <PaginatedTable
          tableName="transactions"
          queryModifier={(q) => q.eq('user_id', profile?.id)}
          pageSize={5}
          columns={[
            { key: 'type', label: 'Flow', render: (r) => <span className="capitalize font-black italic text-xs">{r.type}</span> },
            { key: 'amount', label: 'Amount', render: (r) => <span className="font-black text-sm">₹{Math.abs(r.amount)}</span> },
            { key: 'status', label: 'Status', render: (r) => <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded ${r.status === 'completed' ? 'bg-green-50 text-green-600' : 'bg-yellow-50 text-yellow-600'}`}>{r.status}</span> }
          ]}
        />
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden mb-6">
        <button onClick={() => setShowSettings(true)} className="w-full flex items-center justify-between p-5 hover:bg-gray-50 border-b border-gray-50 transition-colors">
          <div className="flex items-center gap-3 text-gray-700"><Settings size={20} /><span className="font-bold text-sm">Account Settings</span></div>
          <span className="text-gray-300">→</span>
        </button>
        <button onClick={() => { signOut(); window.location.href = '/'; }} className="w-full flex items-center justify-between p-5 hover:bg-red-50 transition-colors group">
          <div className="flex items-center gap-3 text-red-600 font-bold text-sm"><LogOut size={20} /><span>Secure Logout</span></div>
        </button>
      </div>

      {showSettings && (
        <div className="fixed inset-0 z-[80] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-in fade-in">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl">
            <h3 className="text-xl font-black italic uppercase mb-6 text-gray-800">Profile Settings</h3>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black uppercase text-gray-500 tracking-widest block mb-1">Username</label>
                <input type="text" value={settingsForm.username} onChange={e => setSettingsForm({...settingsForm, username: e.target.value})} className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 font-bold text-gray-800 focus:outline-none focus:border-red-500" />
              </div>
              <div className="flex gap-3 pt-4">
                <button onClick={() => setShowSettings(false)} className="flex-1 bg-gray-100 text-gray-600 font-bold py-3 rounded-xl">Cancel</button>
                <button onClick={handleSaveSettings} className="flex-1 bg-red-600 text-white font-bold py-3 rounded-xl shadow-lg active:scale-95">Save</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useGameStore, GameResult } from '../store/gameStore';
import { useAuthStore } from '../store/authStore';
import PaginatedTable from './PaginatedTable';

function ColorDot({ color }: { color: GameResult['color'] }) {
  if (color === 'red-violet') {
    return (
      <div className="flex gap-0.5 items-center justify-center">
        <span className="w-2.5 h-2.5 rounded-full bg-red-500 inline-block" />
        <span className="w-2.5 h-2.5 rounded-full bg-violet-500 inline-block" />
      </div>
    );
  }
  if (color === 'green-violet') {
    return (
      <div className="flex gap-0.5 items-center justify-center">
        <span className="w-2.5 h-2.5 rounded-full bg-green-500 inline-block" />
        <span className="w-2.5 h-2.5 rounded-full bg-violet-500 inline-block" />
      </div>
    );
  }
  const colorMap = { green: 'bg-green-500', red: 'bg-red-500', violet: 'bg-violet-500' };
  return <span className={`w-3 h-3 rounded-full ${colorMap[color as 'green' | 'red' | 'violet']} inline-block`} />;
}

function NumberBall({ number, color }: { number: number; color: GameResult['color'] }) {
  let textColor = 'text-red-500';
  if (color === 'green' || color === 'green-violet') textColor = 'text-green-500';
  if (color === 'violet') textColor = 'text-violet-500';
  return <span className={`font-black text-sm ${textColor}`}>{number}</span>;
}

