resyncTimers: () => {
  set(state => {
    const updatedSessions = { ...state.sessions };
    const updatedCounters = { ...state.counters };
    for (const st of SESSION_ORDER) {
      const { durationSeconds } = SESSION_CONFIGS[st];
      const now = new Date();
      const startOfDay = new Date(now);
      startOfDay.setUTCHours(0, 0, 0, 0);
      const elapsedSeconds = Math.floor((now.getTime() - startOfDay.getTime()) / 1000);
      const correctCounter = Math.floor(elapsedSeconds / durationSeconds) + 1;
      const correctTimeLeft = durationSeconds - (elapsedSeconds % durationSeconds);

      if (state.counters[st] !== correctCounter) {
        // A period was missed. We must fast-forward the state to present reality.
        updatedCounters[st] = correctCounter;
        updatedSessions[st] = {
          ...updatedSessions[st],
          period: generatePeriod(st, correctCounter),
          timeLeft: correctTimeLeft,
          isAcceptingBets: correctTimeLeft > 5,
          isResolving: false,
          currentBets: [],
        };
      } else {
        // Same period, just correct the clock drift
        updatedSessions[st] = {
          ...updatedSessions[st],
          timeLeft: correctTimeLeft,
          isAcceptingBets: correctTimeLeft > 5,
        };
      }
    }
    return { sessions: updatedSessions, counters: updatedCounters };
  });
},

async tick() {
  const state = get();
  const updatedSessions = { ...state.sessions };
  const sessionsToResolve: SessionType[] = [];

  // Calculate actual time left globally to prevent tab-sleep desync
  for (const st of SESSION_ORDER) {
    const session = { ...updatedSessions[st] };
    const { durationSeconds } = SESSION_CONFIGS[st];
    const now = new Date();
    const startOfDay = new Date(now);
    startOfDay.setUTCHours(0, 0, 0, 0);
    const elapsedSeconds = Math.floor((now.getTime() - startOfDay.getTime()) / 1000);
    const correctCounter = Math.floor(elapsedSeconds / durationSeconds) + 1;
    const correctTimeLeft = durationSeconds - (elapsedSeconds % durationSeconds);

    // Only update time if we are still in the same period we think we are
    if (state.counters[st] === correctCounter) {
      session.timeLeft = correctTimeLeft;
      if (session.timeLeft <= 5) session.isAcceptingBets = false;

      // SAFETY NET: Fallback polling for game results when timer is low
      if (session.timeLeft > 0 && session.timeLeft < 15 && session.timeLeft % 5 === 0) {
        get().fetchHistoryForSession(st).then();
      }

      if (session.timeLeft <= 0 && !session.isResolving) {
        sessionsToResolve.push(st);
        session.isResolving = true;
      }
    } else if (!session.isResolving) {
      // Tab was asleep and we entirely missed a period! Force resolve the OLD period first.
      sessionsToResolve.push(st);
      session.isResolving = true;
      // Keep timeLeft at 0 so UI stays frozen until DB syncs
      session.timeLeft = 0;
    }

    updatedSessions[st] = session;
  }

  set({ sessions: updatedSessions });

  for (const st of sessionsToResolve) {
    const session = updatedSessions[st];

    try {
      const { data: forced, error: forcedError } = await supabase
        .from('forced_results')
        .select('*')
        .eq('session_type', st)
        .eq('period', session.period)
        .maybeSingle();

      let resultNumber: number;
      let resultColor: string;
      let resultBigSmall: string;

      if (forced) {
        resultNumber = forced.number;
        resultColor = forced.color;
        resultBigSmall = forced.big_small;
        await supabase.from('forced_results').delete().eq('id', forced.id).catch(() => {});
      } else {
        resultNumber = computeHouseResult(session.currentBets);
        resultColor = getColorForNumber(resultNumber);
        resultBigSmall = getSizeForNumber(resultNumber);
      }

      const result: GameResult = {
        period: session.period,
        number: resultNumber,
        color: resultColor as any,
        big_small: resultBigSmall as any,
        session_type: st,
        timestamp: Date.now(),
      };

      const { error: insertError } = await supabase.from('games').insert([{
        period: result.period,
        number: result.number,
        color: result.color,
        big_small: result.big_small,
        session_type: result.session_type,
      }]);

      if (insertError && insertError.code !== '23505') {
         console.error('Failed to save game result:', insertError);
      }

      set(curr => {
        const newUser = curr.user ? { ...curr.user } : null;
        const newMyBets = [...curr.myBets];
        let totalWin = 0;
        let totalLoss = 0;
        let hadBetInSession = session.currentBets.length > 0;

        for (const bet of session.currentBets) {
          const payout = calculateWin(bet, resultNumber);
          if (payout > 0 && newUser) {
            totalWin += payout;
          } else {
            totalLoss += bet.amount;
          }
          newMyBets.push({ ...bet, result: resultNumber, won: payout > 0, payout });
        }

        if (totalWin > 0 && newUser) {
          supabase.rpc('update_user_balance', {
            p_user_id: newUser.id,
            p_amount: totalWin,
            p_reason: 'win',
            p_details: { period: session.period, session: st }
          }).then();
        }

        if (totalLoss > 0 && newUser) {
          supabase.rpc('process_loss_referral_bonus', {
            p_user_id: newUser.id,
            p_loss_amount: totalLoss
          }).then();
        }

        if (hadBetInSession) {
          if (totalWin > 0) {
            get().addToast('win', `🎉 You won ₹${totalWin.toLocaleString()}! Result: ${resultNumber}`);
          } else {
            get().addToast('loss', `Result: ${resultNumber}. Better luck next time!`);
          }
        }

        // Calculate correct state for the NEXT period directly from real time
        const { durationSeconds } = SESSION_CONFIGS[st];
        const now = new Date();
        const startOfDay = new Date(now);
        startOfDay.setUTCHours(0, 0, 0, 0);
        const elapsedSeconds = Math.floor((now.getTime() - startOfDay.getTime()) / 1000);
        const correctCounter = Math.floor(elapsedSeconds / durationSeconds) + 1;
        const correctTimeLeft = durationSeconds - (elapsedSeconds % durationSeconds);

        return {
          ...curr,
          myBets: newMyBets,
          lastRoundResult: hadBetInSession ? { session: st, won: totalWin > 0, amount: totalWin, result } : curr.lastRoundResult,
          sessions: {
            ...curr.sessions,
            [st]: {
              ...curr.sessions[st],
              period: generatePeriod(st, correctCounter),
              timeLeft: correctTimeLeft,
              isAcceptingBets: correctTimeLeft > 5,
              isResolving: false,
              currentBets: [],
              lastResult: result,
              history: [result, ...curr.sessions[st].history].slice(0, 50),
            }
          },
          counters: { ...curr.counters, [st]: correctCounter }
        };
      });
    } catch (err) {
      console.error('Error resolving round for session:', st, err);
      set(curr => ({
        sessions: {
          ...curr.sessions,
          [st]: {
            ...curr.sessions[st],
            isResolving: false,
          }
        }
      }));
    }
  }
}

